code = """import json

# Load data from storage
docs = json.load(open(var_functions.query_db:26, 'r'))
funding = var_functions.query_db:48

# Create project status lookup from documents
status_lookup = {}
for doc in docs:
    text = doc.get('text', '')
    section = None
    for line in text.split('\n'):
        line = line.strip()
        if 'Design' in line and ('Capital' in line or 'Disaster' in line):
            section = 'design'
        elif 'Construction' in line and ('Capital' in line or 'Disaster' in line):
            section = 'construction'
        elif 'Not Started' in line and ('Capital' in line or 'Disaster' in line):
            section = 'not_started'
        elif section and line and len(line) > 10 and not line.startswith('(') and 'Updates' not in line and 'Schedule' not in line:
            base_name = line.split('(')[0].strip()
            if section == 'construction':
                status_lookup[base_name] = 'completed'
            else:
                status_lookup[base_name] = section

print('Status lookup entries:', len(status_lookup))

# Build results
results = []
for rec in funding:
    project_name = rec['Project_Name']
    base_name = project_name.split('(')[0].strip()
    
    # Get status
    status = 'unknown'
    if base_name in status_lookup:
        status = status_lookup[base_name]
    
    results.append([
        project_name,
        rec['Funding_Source'],
        int(rec['Amount']),
        status
    ])

# Create formatted output
output_lines = []
for name, source, amount, status in sorted(results, key=lambda x: x[0]):
    output_lines.append(f"Project: {name}")
    output_lines.append(f"Funding Source: {source}")
    output_lines.append(f"Amount: ${amount:,}")
    output_lines.append(f"Status: {status}")
    output_lines.append("-" * 70)

result_text = "\n".join(output_lines)
final_result = {
    'count': len(results),
    'result': result_text
}

print('__RESULT__:')
print(json.dumps(final_result))"""

